function generateSummaryReport($pdo) {
    $sql = "SELECT 
                r.status,
                c.category_name,
                COUNT(*) as count,
                SUM(r.amount) as total_amount,
                AVG(r.amount) as avg_amount,
                MIN(r.created_at) as earliest_date,
                MAX(r.created_at) as latest_date
            FROM reports r
            LEFT JOIN categories c ON r.category_id = c.id
            WHERE 1=1";
    
    $params = [];
    
    if (!empty($_POST['date_from'])) {
        $sql .= " AND r.created_at >= :date_from";
        $params[':date_from'] = $_POST['date_from'] . ' 00:00:00';
    }
    
    if (!empty($_POST['date_to'])) {
        $sql .= " AND r.created_at <= :date_to";
        $params[':date_to'] = $_POST['date_to'] . ' 23:59:59';
    }
    
    if (!empty($_POST['status'])) {
        if (is_array($_POST['status'])) {
            $placeholders = [];
            foreach ($_POST['status'] as $index => $status) {
                $key = ':status_' . $index;
                $placeholders[] = $key;
                $params[$key] = $status;
            }
            $sql .= " AND r.status IN (" . implode(',', $placeholders) . ")";
        } else {
            $sql .= " AND r.status = :status";
            $params[':status'] = $_POST['status'];
        }
    }
    
    if (!empty($_POST['category'])) {
        if (is_array($_POST['category'])) {
            $placeholders = [];
            foreach ($_POST['category'] as $index => $category) {
                $key = ':category_' . $index;
                $placeholders[] = $key;
                $params[$key] = $category;
            }
            $sql .= " AND r.category_id IN (" . implode(',', $placeholders) . ")";
        } else {
            $sql .= " AND r.category_id = :category";
            $params[':category'] = $_POST['category'];
        }
    }
    
    $sql .= " GROUP BY r.status, c.category_name";
    
    try {
        $stmt = $pdo->prepare($sql);
        
        foreach ($params as $key => $value) {
            $stmt->bindValue($key, $value);
        }
        
        $stmt->execute();
        $results = $stmt->fetchAll(PDO::FETCH_ASSOC);
        
        return [
            'success' => true,
            'summary' => $results
        ];
        
